# V2 surface (roadmap 1541, spec 1543): builtin types behave as
# classes for type/isinstance/issubclass and the __mro__/__name__/
# __bases__/__qualname__ attributes.

print("=== type(x) is T ===")
print(type(1) is int)
print(type(1.0) is float)
print(type("a") is str)
print(type(b"a") is bytes)
print(type(bytearray(b"a")) is bytearray)
print(type(True) is bool)
print(type([]) is list)
print(type(()) is tuple)
print(type({}) is dict)
print(type(set()) is set)
print(type(frozenset()) is frozenset)
print(type(1 + 2j) is complex)

print("=== type(T) is type ===")
print(type(int) is type)
print(type(float) is type)
print(type(str) is type)
print(type(bool) is type)
print(type(bytes) is type)
print(type(bytearray) is type)
print(type(memoryview) is type)
print(type(list) is type)
print(type(tuple) is type)
print(type(dict) is type)
print(type(set) is type)
print(type(frozenset) is type)
print(type(complex) is type)
print(type(type) is type)

print("=== isinstance(T, type) ===")
print(isinstance(int, type))
print(isinstance(float, type))
print(isinstance(str, type))
print(isinstance(bool, type))
print(isinstance(list, type))
print(isinstance(dict, type))
print(isinstance(tuple, type))
print(isinstance(set, type))
print(isinstance(frozenset, type))
print(isinstance(bytes, type))
print(isinstance(bytearray, type))
print(isinstance(complex, type))
print(isinstance(memoryview, type))
print(isinstance(type, type))


class C:
    pass


print(isinstance(C, type))

print("=== issubclass ===")
print(issubclass(bool, int))
print(issubclass(int, object))
print(issubclass(str, object))
print(issubclass(list, object))
print(issubclass(dict, object))
print(issubclass(bool, object))
print(issubclass(bool, (int, str)))
print(issubclass(bool, (str, int)))
print(issubclass(bool, (str, float)))
print(issubclass(int, str))
print(issubclass(int, bool))

print("=== __name__ / __qualname__ / __module__ ===")
print(int.__name__)
print(str.__name__)
print(bool.__name__)
print(list.__name__)
print(type.__name__)
print(int.__qualname__)
print(int.__module__)

print("=== __mro__ ===")
print(tuple(t.__name__ for t in int.__mro__))
print(tuple(t.__name__ for t in float.__mro__))
print(tuple(t.__name__ for t in str.__mro__))
print(tuple(t.__name__ for t in bool.__mro__))
print(tuple(t.__name__ for t in list.__mro__))
print(tuple(t.__name__ for t in dict.__mro__))
print(tuple(t.__name__ for t in tuple.__mro__))
print(tuple(t.__name__ for t in bytes.__mro__))
print(tuple(t.__name__ for t in bytearray.__mro__))
print(tuple(t.__name__ for t in set.__mro__))
print(tuple(t.__name__ for t in frozenset.__mro__))
print(tuple(t.__name__ for t in complex.__mro__))
print(tuple(t.__name__ for t in memoryview.__mro__))
print(tuple(t.__name__ for t in type.__mro__))

print("=== __bases__ ===")
print(tuple(t.__name__ for t in int.__bases__))
print(tuple(t.__name__ for t in str.__bases__))
print(tuple(t.__name__ for t in bool.__bases__))
print(tuple(t.__name__ for t in list.__bases__))
print(tuple(t.__name__ for t in type.__bases__))
